// SPDX-License-Identifier: GPL-3.0
pragma solidity ^0.8.20;

/**
 * @title StudentRecord
 * @dev A smart contract for managing student academic records.
 * Only the contract owner can add and update student records,
 * while anyone can view student information.
 */
contract StudentRecord {
    address public owner;

    struct Student {
        uint256 id;
        string name;
        uint256 age;
        string course;
        uint256 marks;
        bool exists;
    }

    mapping(uint256 => Student) private students;
    uint256[] private studentIds;

    event StudentAdded(
        uint256 indexed id,
        string name,
        string course,
        uint256 marks
    );

    event StudentUpdated(
        uint256 indexed id,
        string name,
        string course,
        uint256 marks
    );

    event OwnershipTransferred(
        address indexed oldOwner,
        address indexed newOwner
    );

    modifier onlyOwner() {
        require(msg.sender == owner, "Only owner can perform this action");
        _;
    }

    constructor() {
        owner = msg.sender;
        emit OwnershipTransferred(address(0), owner);
    }

    /**
     * @dev Adds a new student record.
     * Only the owner can call this function.
     * @param _id Student ID
     * @param _name Student name
     * @param _age Student age
     * @param _course Student course
     * @param _marks Student marks
     */
    function addStudent(
        uint256 _id,
        string memory _name,
        uint256 _age,
        string memory _course,
        uint256 _marks
    ) public onlyOwner {
        require(!students[_id].exists, "Student record already exists");
        require(_id > 0, "Student ID must be greater than zero");
        require(bytes(_name).length > 0, "Name cannot be empty");
        require(_age > 0, "Age must be greater than zero");
        require(bytes(_course).length > 0, "Course cannot be empty");
        require(_marks <= 100, "Marks must be between 0 and 100");

        students[_id] = Student({
            id: _id,
            name: _name,
            age: _age,
            course: _course,
            marks: _marks,
            exists: true
        });

        studentIds.push(_id);

        emit StudentAdded(_id, _name, _course, _marks);
    }

    /**
     * @dev Updates an existing student record.
     * Only the owner can call this function.
     * @param _id Student ID
     * @param _name Updated student name
     * @param _age Updated student age
     * @param _course Updated student course
     * @param _marks Updated student marks
     */
    function updateStudent(
        uint256 _id,
        string memory _name,
        uint256 _age,
        string memory _course,
        uint256 _marks
    ) public onlyOwner {
        require(students[_id].exists, "Student record does not exist");
        require(bytes(_name).length > 0, "Name cannot be empty");
        require(_age > 0, "Age must be greater than zero");
        require(bytes(_course).length > 0, "Course cannot be empty");
        require(_marks <= 100, "Marks must be between 0 and 100");

        students[_id].name = _name;
        students[_id].age = _age;
        students[_id].course = _course;
        students[_id].marks = _marks;

        emit StudentUpdated(_id, _name, _course, _marks);
    }

    /**
     * @dev Returns a student record by ID.
     * Anyone can call this function.
     * @param _id Student ID
     */
    function getStudent(uint256 _id)
        public
        view
        returns (
            uint256 id,
            string memory name,
            uint256 age,
            string memory course,
            uint256 marks
        )
    {
        require(students[_id].exists, "Student record does not exist");

        Student memory s = students[_id];
        return (s.id, s.name, s.age, s.course, s.marks);
    }

    /**
     * @dev Checks whether a student exists.
     * @param _id Student ID
     */
    function studentExists(uint256 _id) public view returns (bool) {
        return students[_id].exists;
    }

    /**
     * @dev Returns the total number of student records.
     */
    function getStudentCount() public view returns (uint256) {
        return studentIds.length;
    }

    /**
     * @dev Returns all student IDs stored in the contract.
     */
    function getAllStudentIds() public view returns (uint256[] memory) {
        return studentIds;
    }

    /**
     * @dev Transfers ownership to another address.
     * Only current owner can call this function.
     * @param _newOwner Address of new owner
     */
    function transferOwnership(address _newOwner) public onlyOwner {
        require(_newOwner != address(0), "New owner cannot be zero address");

        address oldOwner = owner;
        owner = _newOwner;

        emit OwnershipTransferred(oldOwner, _newOwner);
    }
}

